    """
    Given an array of integers, sort the integers that are between 1 and 9 inclusive,
    reverse the resulting array, and then replace each digit by its corresponding name from
    "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine".

    For example:
      arr = [2, 1, 1, 4, 5, 8, 2, 3]   
            -> sort arr -> [1, 1, 2, 2, 3, 4, 5, 8] 
            -> reverse arr -> [8, 5, 4, 3, 2, 2, 1, 1]
      return ["Eight", "Five", "Four", "Three", "Two", "Two", "One", "One"]

      If the array is empty, return an empty array:
      arr = []
      return []

      If the array has any strange number ignore it:
      arr = [1, -1 , 55] 
            -> sort arr -> [-1, 1, 55]
            -> reverse arr -> [55, 1, -1]
      return = ['One']
    """
    def digit_to_name(num):
        if num < 1 or num > 9:
            return None
        if num == 0:
            return "Zero"
        name = str(num)
        if name == "One":
            return "One"
        elif name == "Two":
            return "Two"
        elif name == "Three":
            return "Three"
        elif name == "Four":
            return "Four"
        elif name == "Five":
            return "Five"
        elif name == "Six":
            return "Six"
        elif name == "Seven":
            return "Seven"
        elif name == "Eight":
            return "Eight"
        elif name == "Nine":
            return "Nine"
        return None

    result = []
    for num in arr:
        name = digit_to_name(num)
        if name is not None:
            result.append(name)
    return result

