    Examples:
    match_parens(['()(', ')']) == 'Yes'
    match_parens([')', ')']) == 'No'
    '''
    def is_good(s):
        count = 0
        for char in s:
            if char == '(':
                count += 1
            elif char == ')':
                count -= 1
                if count < 0:
                    return False
        return count == 0

    def is_possible(lst):
        if len(lst) != 2:
            return False
        s1, s2 = lst
        if not is_good(s1) or not is_good(s2):
            return False
        return is_possible([s1, s2])

    return is_possible(lst)

